+func trimLeadingPackageClause(src []byte) []byte {
+	offset := 0
+	inBlockComment := false
+
+	for offset < len(src) {
+		lineStart := offset
+		for offset < len(src) && src[offset] != '\n' {
+			offset++
+		}
+		lineEnd := offset
+		if offset < len(src) && src[offset] == '\n' {
+			offset++
+		}
+
+		line := bytes.TrimSpace(src[lineStart:lineEnd])
+		if inBlockComment {
+			if end := bytes.Index(line, []byte("*/")); end >= 0 {
+				inBlockComment = false
+				if trailing := bytes.TrimSpace(line[end+2:]); len(trailing) > 0 {
+					if bytes.HasPrefix(trailing, []byte("package ")) {
+						return skipBlankLines(src[offset:])
+					}
+					return src
+				}
+			}
+			continue
+		}
+
+		switch {
+		case len(line) == 0:
+			continue
+		case bytes.HasPrefix(line, []byte("//")):
+			continue
+		case bytes.HasPrefix(line, []byte("/*")):
+			if end := bytes.Index(line, []byte("*/")); end >= 0 {
+				if trailing := bytes.TrimSpace(line[end+2:]); len(trailing) > 0 {
+					if bytes.HasPrefix(trailing, []byte("package ")) {
+						return skipBlankLines(src[offset:])
+					}
+					return src
+				}
+				continue
+			}
+			inBlockComment = true
+			continue
+		case bytes.HasPrefix(line, []byte("package ")):
+			return skipBlankLines(src[offset:])
+		default:
+			return src
+		}
+	}
