+func skipBlankLines(src []byte) []byte {
+	for len(src) > 0 {
+		lineEnd := bytes.IndexByte(src, '\n')
+		if lineEnd < 0 {
+			if len(bytes.TrimSpace(src)) == 0 {
+				return nil
+			}
+			return src
+		}
+		if len(bytes.TrimSpace(src[:lineEnd])) != 0 {
