package main

import (
	"os"
	"path/filepath"

	"github.com/zchee/spanner-manager/codegen"
)

func main() {
	outDir := filepath.Join("$tmpdir", "models")
	if err := os.WriteFile(filepath.Join(outDir, "spanner_header.spanner.go"), []byte("package models\nconst stale = true\n"), 0o644); err != nil {
		panic(err)
	}
	schema := &codegen.Schema{Types: []codegen.Type{
		{
			Name: "Users",
			Table: "Users",
			Fields: []codegen.Field{
				{Name: "ID", ColumnName: "id", GoType: "int64", SpannerType: "INT64", BaseSpannerType: "INT64", NotNull: true, IsPrimaryKey: true},
			},
		},
	}}
	if err := codegen.NewGenerator(codegen.Options{
		OutDir: outDir,
		PackageName: "models",
	}).Generate(schema); err != nil {
		panic(err)
	}
}
EOF
go run "$tmpdir/repro.go"
printf '%s\n' '---files---'
find "$tmpdir/models" -maxdepth 1 -type f | sort | sed "s#$tmpdir/models/##"
`;
const r = await run(shell, 180000);
text(typeof r === 'string' ? r : JSON.stringify(r, null, 2));

